import React, {type ReactNode, useState} from 'react';
import {
    Box,
    Flex,
    HStack,
    Heading,
    Text,
    Button,
    KitsInputText,
    KitsInputNumber,
    KitsInputTextarea,
    FormSelect,
    useLanguage,
} from '../../_compat';
import type {IDetailListProps, IDetailItem} from '@lmb-it/kitsconcerto-types';

const DetailList = <T extends Record<string, any>>({
    title,
    description,
    data,
    items,
    headerActions,
    itemActions,
}: IDetailListProps<T>) => {
    const {t} = useLanguage();
    const [editingField, setEditingField] = useState<keyof T | null>(null);
    const [draftValue, setDraftValue] = useState<any>(null);
    const [isSaving, setIsSaving] = useState(false);

    const handleEdit = (item: IDetailItem<T>) => {
        setEditingField(item.name);
        setDraftValue(data[item.name]);
    };

    const handleCancel = () => {
        setEditingField(null);
        setDraftValue(null);
    };

    const handleSave = async (item: IDetailItem<T>) => {
        if (item.onSave) {
            setIsSaving(true);
            try {
                await item.onSave(item.name, draftValue);
                setEditingField(null);
            } finally {
                setIsSaving(false);
            }
        } else {
            setEditingField(null);
        }
    };

    const renderControl = (item: IDetailItem<T>) => {
        const commonProps = {
            value: draftValue,
            onChange: (e: any) => setDraftValue(e.target ? e.target.value : e.value),
            w: '100%',
            ...item.inputProps,
        };

        switch (item.type) {
            case 'number':
                return (
                    <KitsInputNumber
                        value={draftValue}
                        onChange={(e) => setDraftValue(e.value)}
                        style={{width: '100%'}}
                        {...item.inputProps}
                    />
                );
            case 'textarea':
                return <KitsInputTextarea {...commonProps} rows={3} autoResize/>;
            case 'select':
                return (
                    <FormSelect
                        shape="dropdown"
                        {...commonProps}
                        list={item.list || []}
                        labelKey={item.labelKey}
                        valueKey={item.valueKey}
                    />
                );
            case 'multiselect':
                return (
                    <FormSelect
                        shape="multiselect"
                        {...commonProps}
                        list={item.list || []}
                        labelKey={item.labelKey}
                        valueKey={item.valueKey}
                    />
                );
            case 'text':
            default:
                return <KitsInputText {...commonProps} />;
        }
    };

    // @ts-ignore
    // @ts-ignore
    return (
        <Box bgColor="var(--surface-0)" p="1.5rem" borderRadius="0.75rem">
            {/* Header Area */}
            {(title || description || headerActions) && (
                <HStack justifyContent="space-between" alignItems="flex-start" mb="1.5rem">
                    <Box>
                        {title && (
                            typeof title === 'string'
                                ? (
                                    <Heading as="h2" fontSize="1.5rem" fontWeight="600"
                                             fontColor="var(--text-900)"
                                             mb={description ? '0.5rem' : '0'}>
                                        {title}
                                    </Heading>
                                )
                                : title
                        )}
                        {description && (
                            typeof description === 'string'
                                ? (
                                    <Text as="p" fontColor="var(--text-500)" fontSize="0.875rem">
                                        {description}
                                    </Text>
                                )
                                : description
                        )}
                    </Box>
                    {headerActions && <Box>{headerActions}</Box>}
                </HStack>
            )}

            {/* List Area */}
            <Box as="ul" p="0" m="0" style={{listStyle: 'none'}}>
                {items.map((item, index) => {
                    const isEditing = editingField === item.name;
                    const isLast = index === items.length - 1;

                    return (
                        <Flex
                            key={item.name as string}
                            as="li"
                            alignItems="center"
                            py="1rem"
                            // justifyContent={'center'}
                            px="0.5rem"
                            style={{
                                borderTop: '1px solid var(--surface-200)',
                                borderBottom: isLast ? '1px solid var(--surface-200)' : 'none',
                            }}
                            flexWrap="wrap"
                        >
                           <Flex w={['50%', null, '85%']} flexDirection={['column', 'row']}>
                               {/* Label Column */}
                               <Text
                                   m={0}
                                   w={['50%', null, '16.666%']}
                                   fontColor="var(--surface-500)"
                                   fontWeight="500"
                                   fontSize="0.875rem"
                               >
                                   {item.label}
                               </Text>

                               {/* Value / Edit Control Column */}
                               <Box
                                   w={['100%', null, '66.666%']}
                                   fontColor="var(--text-900)"
                                   lineHeight={item.type === 'textarea' ? 1.5 : undefined}
                               >
                                   {isEditing
                                       ? renderControl(item)
                                       : item.body
                                           ? item.body(data[item.name], data)
                                           : (data[item.name] as ReactNode)}
                               </Box>
                           </Flex>

                            {/* Actions Column */}
                            <Flex
                                w={['50%', null, '15%']}
                                justifyContent="flex-end"
                                alignItems="center"
                                gap="0.5rem"
                            >
                                {itemActions && !isEditing && itemActions(item, data)}

                                {item.editable && !isEditing && (
                                    <Button
                                        label={t("edit")}
                                        icon="pencil"
                                        severity="contrast"
                                        outlined
                                        onClick={() => handleEdit(item)}
                                    />
                                )}

                                {isEditing && (
                                    <HStack gap="0.25rem">
                                        <Button
                                            icon="pi pi-check"
                                            severity="success"
                                            loading={isSaving}
                                            onClick={() => handleSave(item)}
                                            aria-label={t("save")}
                                        />
                                        <Button
                                            icon="pi pi-times"
                                            severity="secondary"
                                            disabled={isSaving}
                                            onClick={handleCancel}
                                            aria-label={t("cancel")}
                                        />
                                    </HStack>
                                )}
                            </Flex>
                        </Flex>
                    );
                })}
            </Box>
        </Box>
    );
}

export default DetailList
